// Parse library_id from the chat message and batch BibTeX entries
const BATCH_SIZE = 190;

// Extract library_id from chat input
const chatInput = $('When chat message received').first().json.chatInput || '';
const libMatch = chatInput.match(/library_id\s*[:=]\s*(\d+)/i);
const library_id = libMatch ? parseInt(libMatch[1]) : null;

if (!library_id) {
  return [{ json: { error: 'No library_id found. Include library_id: <number> in your message.' } }];
}

// Get BibTeX content
const inputString = items[0].json.data;
if (!inputString || typeof inputString !== 'string') {
  return [{ json: { error: "No valid 'data' property found in input." } }];
}

// Split into individual entries
const rawEntries = inputString.split(/(?=@\w+\{)/g);
const cleanEntries = rawEntries
  .map(entry => entry.trim())
  .filter(entry => entry.length > 5 && entry.startsWith('@'));

// Batch the entries
const batches = [];
for (let i = 0; i < cleanEntries.length; i += BATCH_SIZE) {
  const batchContent = cleanEntries.slice(i, i + BATCH_SIZE);
  batches.push({
    json: {
      batch_index: batches.length + 1,
      total_entries: cleanEntries.length,
      entries_in_batch: batchContent.length,
      library_id: library_id,
      data: batchContent.join('\n\n')
    }
  });
}

return batches;

// Merge all batch outputs sorted by batch_index
const sourceNodeName = 'Abstract Agent';
let allBatches = [];
try { allBatches = $(sourceNodeName).all(); } catch (e) {}

if (allBatches.length <= 1) {
  allBatches = [];
  let runIndex = 0;
  let keepLooking = true;
  while (keepLooking) {
    try {
      const item = $(sourceNodeName).first(0, runIndex);
      if (item) { allBatches.push(item); runIndex++; }
      else { keepLooking = false; }
    } catch (e) { keepLooking = false; }
    if (runIndex > 500) keepLooking = false;
  }
}

allBatches.sort((a, b) => parseInt(a.json.batch_index || 0) - parseInt(b.json.batch_index || 0));

const mergedContent = allBatches
  .map(item => {
    let text = item.json.output || item.json.text || item.json.data || '';
    if (typeof text !== 'string') text = JSON.stringify(text);
    return text.replace(/^```bibtex\s*/i, '').replace(/```$/i, '').trim();
  })
  .filter(text => text.length > 0)
  .join('\n\n');

// Preserve library_id from first batch
const library_id = allBatches.length > 0 ? (allBatches[0].json.library_id || null) : null;

return [{ json: {
  fileName: 'processed_bibliography.bib',
  data: mergedContent,
  library_id: library_id,
  total_batches_found: allBatches.length
} }];

// Deduplicate BibTeX entries by citation_key + abstract signature
const items = $input.all();
if (!items.length || !items[0].json.data) {
  return [{ json: { error: 'No data found.' } }];
}

let fullContent = items[0].json.data;
const library_id = items[0].json.library_id;
const rawEntries = fullContent.split(/(?=@\w+\s*\{)/g);
const finalEntries = [];
const seenSignatures = new Set();
let duplicatesRemoved = 0;

for (const entry of rawEntries) {
  const trimmed = entry.trim();
  if (trimmed.length < 20) continue;

  const keyMatch = trimmed.match(/@\w+\s*\{\s*([^,]+),/);
  const key = keyMatch ? keyMatch[1].trim() : 'UNKNOWN_KEY';
  const abstractMatch = trimmed.match(/abstract\s*=\s*\{([\s\S]*?)\}/);
  const abstract = abstractMatch ? abstractMatch[1].trim() : 'NO_ABSTRACT';
  const signature = `${key}|||${abstract}`;

  if (seenSignatures.has(signature)) {
    duplicatesRemoved++;
    continue;
  }
  seenSignatures.add(signature);
  finalEntries.push(trimmed);
}

const finalContent = finalEntries.join('\n\n');
const markdownDoc = `# Annotated Bibliography\n\n\`\`\`bibtex\n${finalContent.trim()}\n\`\`\`\n`;

return [{ json: {
  fileName: 'bibliography.md',
  data: markdownDoc,
  raw_bibtex: finalContent,
  library_id: library_id,
  stats: { total_entries_kept: finalEntries.length, duplicates_removed: duplicatesRemoved }
} }];

// Parse BibTeX entries into individual citation objects for Supabase
const cleanerOutput = $('Bib Cleaner').first();
const rawBibtex = cleanerOutput.json.raw_bibtex || cleanerOutput.json.data || '';
const library_id = cleanerOutput.json.library_id;
const driveFile = $('Upload to Google Drive').first();
const gdrive_url = driveFile?.json?.webContentLink || null;

const entries = rawBibtex.split(/(?=@\w+\s*\{)/g).filter(e => e.trim().length > 20);
const citations = [];

for (const entry of entries) {
  const typeMatch = entry.match(/^@(\w+)\s*\{/);
  const keyMatch = entry.match(/^@\w+\s*\{\s*([^,]+),/);

  const getField = (name) => {
    const re = new RegExp(name + '\\s*=\\s*\\{([\\s\\S]*?)\\}', 'i');
    const m = entry.match(re);
    return m ? m[1].trim() : null;
  };

  const yearField = getField('year');
  const yearNum = yearField ? parseInt(yearField) : null;

  citations.push({
    json: {
      library_id: library_id,
      citation_key: keyMatch ? keyMatch[1].trim() : 'unknown',
      entry_type: typeMatch ? typeMatch[1].toLowerCase() : 'misc',
      title: getField('title') || 'Untitled',
      authors: getField('author'),
      year: (yearNum && !isNaN(yearNum)) ? yearNum : null,
      journal: getField('journal') || getField('booktitle'),
      abstract: getField('abstract'),
      doi: getField('doi'),
      arxiv_id: getField('eprint') || getField('arxivid'),
      url: getField('url'),
      bibtex_raw: entry.trim(),
      verification_status: 'unverified',
      source: 'bibtex_import'
    }
  });
}

return citations;

